import { useEffect, useState } from 'react';

function Home() {
  const [imageLoaded, setImageLoaded] = useState(false);

  useEffect(() => {
    const img = new Image();
    img.src = '/fondo6.jpg';
    img.onload = () => setImageLoaded(true);
  }, []);

  return (
    <div className="w-full h-screen flex flex-col items-center justify-center relative overflow-hidden">
      {/* Fondo de baja calidad */}
      <div
        className={`absolute inset-0 bg-cover bg-center transition-opacity duration-1000 ease-in-out ${
          imageLoaded ? 'opacity-0' : 'opacity-40'
        }`}
        style={{
          backgroundImage: "url('/fondo6_lazy.jpg')",
        }}
      />

      {/* Fondo de alta calidad */}
      <div
        className={`absolute inset-0 bg-cover bg-center transition-opacity duration-1000 ease-in-out ${
          imageLoaded ? 'opacity-40' : 'opacity-0'
        }`}
        style={{
          backgroundImage: "url('/fondo6.jpg')",
        }}
      />

      {/* Contenido principal */}
      <div className="relative z-10 flex flex-col gap-10 items-center px-4 md:px-10 lg:flex-row lg:gap-20 lg:justify-between w-full h-full">
        {/* Sección izquierda (imágenes) */}

        <div className="relative flex flex-col items-center">
          {/* Imagen principal */}
          <img
            className="rounded-lg w-[125px] h-[150px] md:w-[200px] md:h-[250px] lg:w-[250px] lg:h-[300px] transition-transform transform hover:scale-105"
            src="/Foto1.HEIC"
            alt="Imagen 1"
          />

          {/* Imagen secundaria arriba a la izquierda */}
          <img
            className="absolute rounded-lg w-[60px] h-[80px] top-[30px] left-[-50px] md:w-[80px] md:h-[100px] lg:w-[100px] lg:h-[120px] animate-float"
            src="/Foto5.JPEG"
            alt="Imagen 2"
          />

          {/* Imagen secundaria abajo a la derecha */}
          <img
            className="absolute rounded-lg w-[60px] h-[80px] bottom-[-20px] right-[-30px] md:w-[80px] md:h-[100px] lg:w-[100px] lg:h-[120px] animate-float"
            src="/Foto2.HEIC"
            alt="Imagen 3"
          />
        </div>

        {/* Sección central (texto) */}
        <div className="text-center flex flex-col items-center justify-center gap-4">
          <h3 className="text-[#6d7561] text-xl md:text-2xl lg:text-3xl font-medium">
            ¡Los invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-2xl md:text-4xl lg:text-5xl font-bold">
            Anto & Kevin
          </h1>
          <a
            target="_blank"
            rel="noopener noreferrer"
            href="https://p02jvynd.forms.app/formularioinvitados"
            className="text-[#6d7561] text-lg md:text-xl underline hover:text-[#6d756190]"
          >
            Confirmar asistencia &gt;
          </a>
        </div>

        {/* Sección derecha (imágenes) */}
        <div className="flex flex-col items-center gap-5 lg:gap-10">
          <img
            className="rounded-lg w-[125px] h-[150px] md:w-[200px] md:h-[250px] lg:w-[250px] lg:h-[300px] transition-transform transform hover:scale-105"
            src="/Foto3.JPEG"
            alt="Imagen 4"
          />
          <img
            className="absolute rounded-lg w-[75px] h-[100px] top-[60%] right-[-50px] md:w-[100px] md:h-[150px] lg:w-[150px] lg:h-[200px] animate-float"
            style={{
              transform: 'translateX(50%) translateY(-10px)',
            }}
            src="/Foto4.JPEG"
            alt="Imagen 5"
          />
        </div>
      </div>
    </div>
  );
}

export default Home;
